#include <stdio.h>
#include <string.h>
#define MAX 55

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[MAX];
        scanf("%s", s);
        int n = strlen(s);
        int count = 0;
        char ans[MAX];
        for (int i = 0; i < (1 << n); i++) {
            char temp[MAX];
            for (int j = 0; j < n; j++) {
                temp[j] = (i & (1 << j)) ? '1' : '0';
            }
            temp[n] = '\0';
            int flag = 1;
            for (int j = 0; j < n; j++) {
                int cnt = 0;
                if (j > 0 && temp[j - 1] == '1') cnt++;
                if (j < n - 1 && temp[j + 1] == '1') cnt++;
                if (j == 0 && temp[n - 1] == '1') cnt++;
                if (j == n - 1 && temp[0] == '1') cnt++;
                if ((temp[j] == '1' && cnt != 1) || (temp[j] == '0' && cnt == 1)) {
                    flag = 0;
                    break;
                }
            }
            if (flag) {
                if (count == 1) {
                    printf("Multiple solutions\n");
                    break;
                }
                strcpy(ans, temp);
                count++;
            }
        }
        if (count == 0) printf("No solution\n");
        else if(count > 1) printf("Multiple solutions\n");
        else printf("%s\n", ans);
    }
    return 0;
}

