        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = s.length();
            int count = 0;
            String ans = "";
            for (int i = 0; i < (1 << n); i++) {
                StringBuilder temp = new StringBuilder();
                for (int j = 0; j < n; j++) {
                    temp.append((i & (1 << j)) == 0 ? '0' : '1');
                }
                int flag = 1;
                for (int j = 0; j < n; j++) {
                    int cnt = 0;
                    if (j > 0 && temp.charAt(j - 1) == '1') cnt++;
                    if (j < n - 1 && temp.charAt(j + 1) == '1') cnt++;
                    if (j == 0 && temp.charAt(n - 1) == '1') cnt++;
                    if (j == n - 1 && temp.charAt(0) == '1') cnt++;
                    if ((temp.charAt(j) == '1' && cnt != 1) || (temp.charAt(j) == '0' && cnt == 1)) {
                        flag = 0;
                        break;
                    }
                }
                if (flag) {
                    if (count == 1) {
                        System.out.println("Multiple solutions");
                        break;
                    }
                    ans = temp.toString();
                    count++;
                }
            }
            if (count == 0) System.out.println("No solution");
            else if(count > 1) System.out.println("Multiple solutions");
            else System.out.println(ans);
        }
    }
}

